// eslint-disable-next-line @typescript-eslint/no-explicit-any
export async function onRequest(context: any) {
  try {
    // 遅延インポートでモジュール初期化エラーを onRequest 内で捕捉する
    const { createPagesFunctionHandler } = await import('@react-router/cloudflare')
    // @ts-ignore - generated by react-router build
    const build = await import('../build/server')

    const handler = createPagesFunctionHandler({
      build,
      getLoadContext: (ctx: any) => {
        const env = ctx.env as Record<string, string | undefined>
        if (env.DATABASE_URL) {
          ;(globalThis as Record<string, unknown>).__DATABASE_URL = env.DATABASE_URL
        }
        return { cloudflare: env }
      },
    })

    return await handler(context)
  } catch (err) {
    const msg = err instanceof Error ? `${err.message}\n\n${err.stack}` : String(err)
    return new Response(`[Worker Error]\n${msg}`, {
      status: 500,
      headers: { 'Content-Type': 'text/plain; charset=utf-8' },
    })
  }
}
